class Solution:
    def reorderedPowerOf2(self, n: int) -> bool:
        count = [0] * 10
        while n:
            count[n % 10] += 1
            n //= 10
        n = 1
        for i in range(10):
            while count[i]:
                n *= 2
                count[i] -= 1
                if n > 2 ** 30:
                    return False
        return n == 2 ** 30

